1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const CURSED_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const LOYALTY_DISCOUNT_RATE = 0.2;
7	const LOYALTY_YEARS_THRESHOLD = 2;
8	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
9	const BLOCK_SIZE = 3;
10	const BLOCK_PREMIUM = 60;
11	
12	const BASE_PREMIUMS: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	  rune: 25,
18	  moonstone: 25,
19	};
20	
21	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
22	
23	const INSURANCE_VALUE_MULTIPLIER = 10;
24	const insuranceValueFor = (type: string): number => BASE_PREMIUMS[type] * INSURANCE_VALUE_MULTIPLIER;
25	const DEDUCTIBLE = 100;
26	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
27	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
28	const CAP_MULTIPLIER = 2;
29	
30	type Item = { type: string; cursed?: boolean; enchantment?: number };
31	type QuoteStep = { op: "quote"; items: Array<Item> };
32	type Damage = { itemType: string; amount: number };
33	type ClaimStep = { op: "claim"; policy: number; incident: { cause: string; damages: Array<Damage> } };
34	type Step = QuoteStep | ClaimStep;
35	type Customer = { yearsWithMHPCO: number };
36	type Scenario = { customer: Customer; steps: Array<Step> };
37	type Policy = { items: Array<Item>; remainingCap: number };
38	
39	const sum = (xs: number[]): number => xs.reduce((a, b) => a + b, 0);
40	
41	const countBy = <T>(items: T[], keyOf: (item: T) => string): Record<string, number> => {
42	  const counts: Record<string, number> = {};
43	  for (const item of items) {
44	    const key = keyOf(item);
45	    counts[key] = (counts[key] ?? 0) + 1;
46	  }
47	  return counts;
48	};
49	
50	const typeOf = (item: Item): string => item.type;
51	
52	const qualifiesForBlockDiscount = (type: string, count: number): boolean =>
53	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;
54	
55	const subtotalForType = (type: string, count: number): number =>
56	  qualifiesForBlockDiscount(type, count) ? BLOCK_PREMIUM : count * BASE_PREMIUMS[type];
57	
58	const policyBaseFor = (items: Item[]): number =>
59	  sum(Object.entries(countBy(items, typeOf)).map(([type, count]) => subtotalForType(type, count)));
60	
61	const hasEnchantmentAtLeast = (item: Item, threshold: number): boolean =>
62	  (item.enchantment ?? 0) >= threshold;
63	
64	const isHighlyEnchanted = (item: Item): boolean =>
65	  hasEnchantmentAtLeast(item, HIGH_ENCHANTMENT_THRESHOLD);
66	
67	const surchargeRate = (item: Item): number =>
68	  (item.cursed ? CURSED_SURCHARGE_RATE : 0) +
69	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);
70	
71	const itemSurcharge = (item: Item): number => BASE_PREMIUMS[item.type] * surchargeRate(item);
72	
73	const itemSurchargesFor = (items: Item[]): number => sum(items.map(itemSurcharge));
74	
75	const qualifiesForLoyaltyDiscount = (customer: Customer): boolean =>
76	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
77	
78	const loyaltyDiscountFor = (policyBase: number, customer: Customer): number =>
79	  qualifiesForLoyaltyDiscount(customer) ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
80	
81	const firstInsuranceSurchargeFor = (policyBase: number): number =>
82	  policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
83	
84	const isFollowUpQuote = (quoteIndex: number): boolean => quoteIndex > 0;
85	
86	const followUpDiscountFor = (policyBase: number, quoteIndex: number): number =>
87	  isFollowUpQuote(quoteIndex) ? policyBase * FOLLOW_UP_DISCOUNT_RATE : 0;
88	
89	const quotePremium = ({ items }: QuoteStep, customer: Customer, quoteIndex: number): number => {
90	  const policyBase = policyBaseFor(items);
91	  const surcharges = itemSurchargesFor(items) + firstInsuranceSurchargeFor(policyBase);
92	  const discounts = loyaltyDiscountFor(policyBase, customer) + followUpDiscountFor(policyBase, quoteIndex);
93	  return Math.ceil(policyBase + surcharges - discounts + PROCESSING_FEE);
94	};
95	
96	const insuranceSumFor = (items: Item[]): number =>
97	  sum(items.map((item) => insuranceValueFor(item.type)));
98	
99	const payoutRateFor = (item: Item): number =>
100	  hasEnchantmentAtLeast(item, HIGH_ENCHANTMENT_PAYOUT_THRESHOLD) ? HIGH_ENCHANTMENT_PAYOUT_RATE : 1;
101	
102	const insuredItemOfType = (policy: Policy, itemType: string): Item =>
103	  policy.items.find((i) => i.type === itemType)!;
104	
105	const payoutForDamage = (damage: Damage, policy: Policy): number =>
106	  Math.floor(damage.amount * payoutRateFor(insuredItemOfType(policy, damage.itemType)) - DEDUCTIBLE);
107	
108	const validateDamageCounts = (damages: Damage[], policy: Policy): void => {
109	  const damageCounts = countBy(damages, (d) => d.itemType);
110	  const insuredCounts = countBy(policy.items, typeOf);
111	  for (const [type, count] of Object.entries(damageCounts)) {
112	    if (count > (insuredCounts[type] ?? 0)) {
113	      throw new Error(`Damage count for '${type}' exceeds insured count`);
114	    }
115	  }
116	};
117	
118	const desiredPayoutFor = (damages: Damage[], policy: Policy): number =>
119	  sum(damages.map((d) => payoutForDamage(d, policy)));
120	
121	const processClaim = (step: ClaimStep, policies: Policy[]): { payout: number; remainingCap: number } => {
122	  const policy = policies[step.policy];
123	  validateDamageCounts(step.incident.damages, policy);
124	  const payout = Math.min(desiredPayoutFor(step.incident.damages, policy), policy.remainingCap);
125	  policy.remainingCap -= payout;
126	  return { payout, remainingCap: policy.remainingCap };
127	};
128	
129	const capFor = (items: Item[]): number => insuranceSumFor(items) * CAP_MULTIPLIER;
130	
131	const newPolicy = (items: Item[]): Policy =>
132	  ({ items, remainingCap: capFor(items) });
133	
134	const isKnownItemType = (type: string): boolean => type in BASE_PREMIUMS;
135	
136	const validateItemTypes = (items: Item[]): void => {
137	  const unknown = items.find((item) => !isKnownItemType(item.type));
138	  if (unknown) throw new Error(`Unknown item type: '${unknown.type}'`);
139	};
140	
141	const processQuote = (step: QuoteStep, customer: Customer, policies: Policy[]): { premium: number } => {
142	  validateItemTypes(step.items);
143	  const premium = quotePremium(step, customer, policies.length);
144	  policies.push(newPolicy(step.items));
145	  return { premium };
146	};
147	
148	export const runScenario = (input: unknown): unknown => {
149	  const scenario = input as Scenario;
150	  const policies: Policy[] = [];
151	  const results = scenario.steps.map((step) =>
152	    step.op === "quote"
153	      ? processQuote(step, scenario.customer, policies)
154	      : processClaim(step, policies)
155	  );
156	  return { results };
157	};
